css:
/* GENERAL FONTS */
.print-format-content {
    font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
    color: #333;
    font-size: 12px;
    line-height: 1.6;
    padding-bottom: 50px; /* Space for footer */
}

/* HEADER */
.header-top-section {
    margin-bottom: 30px;
    border-bottom: 2px solid #2c3e50;
    padding-bottom: 10px;
}
.invoice-title-block { text-align: right; padding-top: 10px; }
.invoice-title-block h1 {
    font-size: 28px;
    color: #2c3e50;
    text-transform: uppercase;
    margin: 0;
    letter-spacing: 1px;
}
.status-badge {
    background-color: #eee;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 10px;
    text-transform: uppercase;
    letter-spacing: 1px;
    display: inline-block;
    margin-top: 5px;
}

/* BOXES */
.label-text {
    color: #7f8c8d;
    font-weight: 600;
    font-size: 11px;
    text-transform: uppercase;
}
.value-text {
    font-size: 13px;
    font-weight: 500;
    margin-bottom: 8px;
}
.highlight-box {
    background-color: #f8f9fa;
    padding: 10px;
    border-radius: 6px;
    border-left: 4px solid #2c3e50;
    margin-top: 10px;
    width: 80%;
}

/* TABLE */
.legal-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 30px;
}
.legal-table th {
    background-color: #2c3e50;
    color: #ffffff;
    padding: 12px 10px;
    text-align: left;
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
}
.legal-table td {
    padding: 12px 10px;
    border-bottom: 1px solid #eeeeee;
    vertical-align: top;
}
.legal-table tr:last-child td {
    border-bottom: 2px solid #2c3e50;
}
.text-right { text-align: right; }

/* TOTALS */
.totals-container {
    display: flex;
    justify-content: flex-end;
    margin-top: 20px;
}
.totals-box { width: 40%; }
.total-row {
    display: flex;
    justify-content: space-between;
    padding: 6px 0;
    border-bottom: 1px solid #eee;
}
.grand-total {
    font-size: 16px;
    font-weight: bold;
    color: #2c3e50;
    border-top: 2px solid #2c3e50;
    border-bottom: none;
    padding-top: 12px;
    margin-top: 5px;
}
.signature-section { margin-top: 50px; text-align: right; }

/* --- PROFESSIONAL FOOTER STYLING --- */

.print-format {
    /* Safe zone for A4 height */
    min-height: 250mm;
    position: relative;
    padding-bottom: 50px; 
}

#footer-html {
    width: 100%;
    
    /* Center alignment */
    text-align: center;
    
    /* THE LINE: Matching the Dark Blue header color */
    border-top: 2px solid #2c3e50; 
    
    /* Spacing around the text */
    padding-top: 15px;
    padding-bottom: 10px;
    
    /* Positioning at bottom of the container */
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    background-color: white;
}

.firm-address {
    /* Typography settings for a clean legal look */
    font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
    font-size: 9px;
    color: #555;
    text-transform: uppercase; /* Makes it look official */
    letter-spacing: 1px;       /* Adds elegance */
    line-height: 1.5;
}
